import os
import re

def count_lines_of_code(directory):
    line_counts = {}
    for root, dirs, files in os.walk(directory):
        for file in files:
            extension = os.path.splitext(file)[1]
            if extension not in line_counts:
                line_counts[extension] = 0
            with open(os.path.join(root, file), 'r') as f:
                lines = f.readlines()
                code_lines = 0
                for line in lines:
                    line = line.strip()
                    if line and not line.startswith('#') and not line.startswith('//'):
                        code_lines += 1
                line_counts[extension] += code_lines
    return line_counts

